import { describe, expect, it } from 'vitest';

import {
  STATELESS_EXTRUSION_WGSL,
  buildAlphaBoundaryWallIndices,
  buildStatelessMeshGrid,
  validateProjectionTextureContract,
} from './stateless-mesh-projection';

describe('stateless mesh projection', () => {
  it('builds a reusable uv grid with front and back surfaces', () => {
    const grid = buildStatelessMeshGrid({ width: 3, height: 2, solid: true });

    expect(grid.vertexCount).toBe(12);
    expect(grid.uv.length).toBe(24);
    expect(Array.from(grid.uv.slice(0, 6))).toEqual([0, 0, 0.5, 0, 1, 0]);
    expect(grid.surfaceIndices.length).toBe(24);
    expect(grid.perimeterWallIndices.length).toBeGreaterThan(0);
  });

  it('validates depth alpha and confidence texture planes', () => {
    const ok = validateProjectionTextureContract({
      width: 2,
      height: 2,
      depth: new Float32Array(4),
      alpha: new Uint8Array(4),
      confidence: new Float32Array(4),
    });

    expect(ok.ok).toBe(true);
    expect(ok.pixelCount).toBe(4);

    const bad = validateProjectionTextureContract({
      width: 2,
      height: 2,
      depth: new Float32Array(3),
      alpha: new Float32Array(4),
    });

    expect(bad.ok).toBe(false);
    expect(bad.errors).toContain('depth length 3 does not match 4');
  });

  it('extracts alpha boundary walls as a separate solid-topology buffer', () => {
    const walls = buildAlphaBoundaryWallIndices({
      width: 3,
      height: 3,
      alpha: new Float32Array([
        0, 0, 0,
        0, 1, 0,
        0, 0, 0,
      ]),
    });

    expect(walls.length).toBe(24);
    expect(Array.from(walls.slice(0, 6))).toEqual([4, 4, 13, 4, 13, 13]);
  });

  it('ships a raw shader contract for vertex texture projection and alpha discard', () => {
    expect(STATELESS_EXTRUSION_WGSL).toContain('textureSampleLevel(depthTex');
    expect(STATELESS_EXTRUSION_WGSL).toContain('discard');
  });
});
